#!/usr/bin/env python3\nimport paramiko\nimport time\n\nHOST = "168.119.79.238"\nPORT = 77\nUSERNAME = "sanliur"\nPASSWORD = "CHANGE_ME_CWP_SSH_PASSWORD"\n\ndef main():\n    ssh = paramiko.SSHClient()\n    ssh.set_missing_host_key_policy(paramiko.AutoAddPolicy())\n    ssh.connect(HOST, port=PORT, username=USERNAME, password=PASSWORD, \n                timeout=20, look_for_keys=False, allow_agent=False)\n    \n    channel = ssh.invoke_shell()\n    time.sleep(2)\n    \n    print("Final DB Fix...")\n    \n    # Export PGPASSWORD and test\n    channel.send("export PGPASSWORD='CHANGE_ME_DB_PASSWORD'\n")\n    time.sleep(1)\n    \n    # Test with password env\n    channel.send("psql -U sanliur_sanliurfa -d sanliur_sanliurfa -h localhost -c 'SELECT 1' 2>&1\n")\n    time.sleep(3)\n    \n    # Update env with password embedded\n    channel.send("cd /home/sanliur/public_html\n")\n    time.sleep(1)\n    \n    # Write new env with password\n    env_lines = [\n        "SITE_URL=https://sanliurfa.com",\n        "NODE_ENV=production", \n        "PORT=6000",\n        "HOST=127.0.0.1",\n        "DATABASE_URL=postgresql://sanliur_sanliurfa:CHANGE_ME_DB_PASSWORD@localhost:5432/sanliur_sanliurfa",\n        "JWT_SECRET=change-this-secret-key-min-32-chars",\n        ""\n    ]\n    \n    for line in env_lines:\n        channel.send(f"echo '{line}' >> .env.new\n")\n        time.sleep(0.3)\n    \n    channel.send("mv .env.new .env.production\n")\n    time.sleep(1)\n    \n    # Restart app\n    channel.send("source ~/.nvm/nvm.sh && pm2 restart sanliurfa\n")\n    time.sleep(5)\n    \n    # Test\n    channel.send("curl -s http://127.0.0.1:4321/api/health 2>&1\n")\n    time.sleep(3)\n    \n    output = ""\n    while channel.recv_ready():\n        output += channel.recv(4096).decode('utf-8', errors='ignore')\n        time.sleep(1)\n    \n    print("RESULT:")\n    print(output[-500:])\n    \n    channel.close()\n    ssh.close()\n\nif __name__ == "__main__":\n    main()\n
